  /// The lock version for the data table itself. Used for optimistic locking and
  /// table versioning. Changes with each update to the table's metadata or
  /// structure.
  final String? dataTable;

  /// The lock version for a specific set of primary values (record). This
  /// includes the default record even if the table does not have any primary
  /// attributes. Used for record-level locking.
  final String? primaryValues;

  /// The lock version for a specific value. Changes each time the individual
  /// value is modified. Used for the finest-grained locking control.
  final String? value;

