/// Represents a data table in Amazon Connect. A data table is a JSON-like data
/// structure where attributes and values are dynamically set by customers.
/// Customers can reference table values within call flows, applications, views,
/// and workspaces to pinpoint dynamic configuration that changes their contact
/// center's behavior in a predetermined and safe way.
///
/// @nodoc
class DataTable {
  /// The Amazon Resource Name (ARN) for the data table. Does not include version
  /// aliases.
  final String arn;

  /// The unique identifier for the data table. Does not include version aliases.
  final String id;

  /// The timestamp when the data table or any of its properties were last
  /// modified.
  final DateTime lastModifiedTime;

  /// The human-readable name of the data table. Must be unique within the
  /// instance and conform to Connect naming standards.
  final String name;

  /// The IANA timezone identifier used when resolving time based dynamic values.
  /// Required even if no time slices are specified.
  final String timeZone;

  /// The timestamp when the data table was created.
  final DateTime? createdTime;

  /// An optional description of the data table's purpose and contents.
  final String? description;

  /// The Amazon Web Services Region where the data table was last modified, used
  /// for region replication.
  final String? lastModifiedRegion;

  /// The lock version information used for optimistic locking and table
  /// versioning. Changes with each update to prevent concurrent modification
  /// conflicts.
  final DataTableLockVersion? lockVersion;

  /// The current status of the data table. One of PUBLISHED or SAVED.
  final DataTableStatus? status;

  /// Key-value pairs for attribute based access control (TBAC or ABAC) and
  /// organization.
  final Map<String, String>? tags;

  /// The data level that concurrent value edits are locked on. One of DATA_TABLE,
  /// PRIMARY_VALUE, ATTRIBUTE, VALUE, and NONE. Determines how concurrent edits
  /// are handled when multiple users attempt to modify values simultaneously.
  final DataTableLockLevel? valueLockLevel;

  /// A unique identifier and alias for customer managed versions (not $LATEST or
  /// $SAVED).
  final String? version;

  /// A description of the customer managed version.
  final String? versionDescription;

  DataTable({
    required this.arn,
    required this.id,
    required this.lastModifiedTime,
    required this.name,
    required this.timeZone,
    this.createdTime,
    this.description,
    this.lastModifiedRegion,
    this.lockVersion,
    this.status,
    this.tags,
    this.valueLockLevel,
    this.version,
    this.versionDescription,
  });

  factory DataTable.fromJson(Map<String, dynamic> json) {
    return DataTable(
      arn: (json['Arn'] as String?) ?? '',
      id: (json['Id'] as String?) ?? '',
      lastModifiedTime:
          nonNullableTimeStampFromJson(json['LastModifiedTime'] ?? 0),
      name: (json['Name'] as String?) ?? '',
      timeZone: (json['TimeZone'] as String?) ?? '',
      createdTime: timeStampFromJson(json['CreatedTime']),
      description: json['Description'] as String?,
      lastModifiedRegion: json['LastModifiedRegion'] as String?,
      lockVersion: json['LockVersion'] != null
          ? DataTableLockVersion.fromJson(
              json['LockVersion'] as Map<String, dynamic>)
          : null,
      status: (json['Status'] as String?)?.let(DataTableStatus.fromString),
      tags: (json['Tags'] as Map<String, dynamic>?)
          ?.map((k, e) => MapEntry(k, e as String)),
      valueLockLevel: (json['ValueLockLevel'] as String?)
          ?.let(DataTableLockLevel.fromString),
      version: json['Version'] as String?,
      versionDescription: json['VersionDescription'] as String?,
    );
  }

  Map<String, dynamic> toJson() {
    final arn = this.arn;
    final id = this.id;
    final lastModifiedTime = this.lastModifiedTime;
    final name = this.name;
    final timeZone = this.timeZone;
    final createdTime = this.createdTime;
    final description = this.description;
    final lastModifiedRegion = this.lastModifiedRegion;
    final lockVersion = this.lockVersion;
    final status = this.status;
    final tags = this.tags;
    final valueLockLevel = this.valueLockLevel;
    final version = this.version;
    final versionDescription = this.versionDescription;
    return {
      'Arn': arn,
      'Id': id,
      'LastModifiedTime': unixTimestampToJson(lastModifiedTime),
      'Name': name,
      'TimeZone': timeZone,
      if (createdTime != null) 'CreatedTime': unixTimestampToJson(createdTime),
      if (description != null) 'Description': description,
      if (lastModifiedRegion != null) 'LastModifiedRegion': lastModifiedRegion,
      if (lockVersion != null) 'LockVersion': lockVersion,
      if (status != null) 'Status': status.value,
      if (tags != null) 'Tags': tags,
      if (valueLockLevel != null) 'ValueLockLevel': valueLockLevel.value,
      if (version != null) 'Version': version,
      if (versionDescription != null) 'VersionDescription': versionDescription,
    };
  }
}

